-- Bad: drop and add in one migration
ALTER TABLE users DROP COLUMN name;
ALTER TABLE users ADD COLUMN full_name VARCHAR(255);

-- Deploy 1: expand
ALTER TABLE users ADD COLUMN full_name VARCHAR(255);
-- (backfill full_name from name)
-- Deploy 2: update app to read full_name
-- Deploy 3: contract
ALTER TABLE users DROP COLUMN name;

users = User.objects.all()
for user in users:
    print(user.orders.count())  # 1 query per user

users = User.objects.prefetch_related('orders').all()
for user in users:
    print(len(user.orders.all()))  # uses prefetched data

@celery_app.task
def send_welcome_email(user_id: int):
    user = User.objects.get(id=user_id)
    # idempotency: check if already sent
    if EmailLog.objects.filter(user_id=user_id, type="welcome").exists():
        return
    email_service.send(user.email, "Welcome!")
    EmailLog.objects.create(user_id=user_id, type="welcome")
